// --- Sub-components ---

const LoadingState = ({ statusMessage }: { statusMessage?: string }): JSX.Element => {
    const { statusMessage: subtext } = useStatusMessage('loading', LOADER_SUBLINES, 2000);
    return (
        <div
            className="omniguide-cr-state omniguide-cr-state--loading"
            role="status"
            aria-live="polite"
        >
            <div className="omniguide-cr-state__ring" aria-hidden="true" />
            <div className="omniguide-cr-state__copy">
                {/* No aria-label here — the visible title is inside this live region
                    and would otherwise be announced twice. */}
                <p className="omniguide-cr-state__title">{statusMessage ?? 'Building your guide…'}</p>
                <p className="omniguide-cr-state__subtext" aria-live="off">{subtext}</p>
            </div>
        </div>
    );
};

const ErrorState = ({ error, onRetry }: { error?: { message?: string; code?: string } | null; onRetry?: () => void }): JSX.Element => {
    const connectionIssue = error?.code === 'WEBSOCKET_ERROR';
    const title = connectionIssue ? 'Unable to connect' : 'Something went wrong';
    const text = connectionIssue
        ? 'The service is currently unavailable. Please try again in a moment.'
        : 'We encountered an error while processing your request. Please try again.';

    return (
        <div className="omniguide-cr-state omniguide-cr-state--error">
            <div className="omniguide-cr-state__icon-wrapper omniguide-cr-state__icon-wrapper--error">
                <WarningIcon />
            </div>
            <h3 className="omniguide-cr-state__title">{title}</h3>
            <p className="omniguide-cr-state__text">{text}</p>
            <button
                type="button"
                className="omniguide-cr-state__retry-btn"
                onClick={onRetry}
            >
                <RefreshIcon />
                <span>Try Again</span>
            </button>
        </div>
    );
};

interface FallbackInfo {
    used?: boolean;
    explanation?: string;
    reason?: string;
    scope?: string;
}

const FallbackNotice = ({ fallbackInfo }: { fallbackInfo?: FallbackInfo | null }): JSX.Element | null => {
    if (!fallbackInfo?.used || !fallbackInfo?.explanation) {
        return null;
    }

    return (
        <div className="omniguide-cr-results__fallback-notice">
            <div className="omniguide-cr-results__fallback-icon">
                <InfoIcon />
                <div>I need your attention...</div>
            </div>
            <p className="omniguide-cr-results__fallback-text">
                {fallbackInfo.explanation}
            </p>
        </div>
    );
};

const NoResultsState = ({ onBack }: { onBack?: () => void }): JSX.Element => (
    <div className="omniguide-cr-state omniguide-cr-state--no-results">
        <div className="omniguide-cr-state__icon-wrapper omniguide-cr-state__icon-wrapper--info">
            <InfoIcon />
        </div>
        <h3 className="omniguide-cr-state__title">No matching products found</h3>
        <p className="omniguide-cr-state__text">
            We couldn't find products that match your specific requirements. Try adjusting your selections to broaden the search.
        </p>
        <button
            type="button"
            className="omniguide-cr-state__retry-btn"
            onClick={onBack}
        >
            <RefreshIcon />
            <span>Try Different Answers</span>
        </button>
    </div>
);

// --- Main component ---

export interface CategoryResultsPanelProps {
    recommendations?: CategoryProduct[];
    isLoading?: boolean;
    error?: { message?: string; code?: string } | null;
    processingStatus?: string;
    statusMessage?: string;
    fallbackInfo?: FallbackInfo | null;
    onBack?: () => void;
    /**
     * Results intro/advice copy from the backend (`review_summary` in the
     * recommendations websocket message). When absent, a category-based
     * default is shown instead.
     */
    introText?: string;
    /** Category / product-type word used to build the default intro copy. */
    categoryName?: string;
    /** Upper-left brand label. Defaults to "Shopping Guide". */
    brandLabel?: string;
    /** Brand mark image URL. When set, replaces the default diamond mark. */
    brandIconUrl?: string;
    questions?: Array<{ id?: string; question?: string; summary?: string }>;
    answeredIntents?: Record<string, { answer: string; [key: string]: unknown }>;
    onStepClick?: (index: number) => void;
    onCollapse?: () => void;
    isCollapsed?: boolean;
    isTruncated?: boolean;
    onTruncatedToggle?: () => void;
    /** Fallback image URL when product has no image (DI for site config) */
    fallbackImage?: string;
    /** DI: analytics callback for start-over action */
    onStartOver?: () => void;
    /** DI: analytics callback when user clicks a product card */
    onProductClick?: (product: CategoryProduct, index: number) => void;
    /** DI: callback for feedback submission */
    onFeedbackSubmit: (data: FeedbackData) => Promise<unknown>;
    /** Show "Top Pick" / "Runner-Up" tags (default: true) */
    showProductTags?: boolean;
    /**
     * Preview mode — the cards are showing a `recommendations_preview` payload
     * with AI-generated copy still streaming in. Renders each card with skeleton
     * placeholders for fields that haven't arrived yet, and suppresses the
     * per-card feedback widget until the final results land.
     */
    isPreview?: boolean;
}

/**
 * CategoryResultsPanel displays personalized product recommendations.
 */
export function CategoryResultsPanel({
    recommendations = [],
    isLoading,
    error,
    statusMessage,
    fallbackInfo,
    onBack,
    introText,
    categoryName,
    brandLabel = 'Shopping Guide',
    brandIconUrl,
    questions = [],
    answeredIntents = {},
    onStepClick,
    onCollapse,
    isCollapsed = false,
    isTruncated = false,
    onTruncatedToggle,
    fallbackImage,
    onStartOver,
    onProductClick,
    onFeedbackSubmit,
    showProductTags,
    isPreview = false,
}: CategoryResultsPanelProps): JSX.Element {
    const CategoryProductCard = useComponent('CategoryProductCard', DefaultCategoryProductCard);

    // Results intro copy: the backend-provided `introText` wins; otherwise a
    // category-aware default that names the category when we know it.
    const introCopy = (introText && introText.trim())
        ? introText
        : categoryName
            ? `We compared the ${categoryName.toLowerCase()} options against your answers and picked the ones that fit best — with the trade-offs laid out.`
            : 'We compared the options against your answers and picked the ones that fit best — with the trade-offs laid out.';

    // Show loading state
    if (isLoading) {
        return (
            <div className="omniguide-cr-results">
                <LoadingState statusMessage={statusMessage} />
            </div>
        );
    }

    // Show error state
    if (error) {
        return (
            <div className="omniguide-cr-results">
                <ErrorState error={error} onRetry={onBack} />
            </div>
        );
    }

    // Show no results state
    if (recommendations.length === 0) {
        return (
            <div className="omniguide-cr-results">
                <NoResultsState onBack={onBack} />
            </div>
        );
    }

    // Show collapsed state (desktop)
    if (isCollapsed) {
        const handleKeyDown = (e: React.KeyboardEvent) => {
            if (e.key === 'Enter' || e.key === ' ') {
                e.preventDefault();
                onCollapse?.();
            }
        };

        return (
            <div className="omniguide-cr-results omniguide-cr-results--collapsed">
                <div className="omniguide-cr-results__header-row">
                    <div className="omniguide-cr-results__header-content">
                        <div className="omniguide-cr-results__title-row">
                            <div className="omniguide-cr-results__icon">
                                <AIIcon />
                            </div>
                            <div className="omniguide-cr-results__title-content">
                                <h2 className="omniguide-cr-results__title">We have some advice.</h2>
                                <button
                                    type="button"
                                    onClick={onCollapse}
                                    onKeyDown={handleKeyDown}
                                    className="omniguide-cr-results__expand-link"
                                    aria-expanded="false"
                                    aria-label="See our recommendations"
                                >
                                    See our recommendations
                                </button>
                            </div>
                        </div>
                        {questions.length > 0 && (
                            <div className="omniguide-cr-results__header-pills">
                                <DiscoveryStepIndicator
                                    currentStep={-1}
                                    totalSteps={questions.length}
                                    answeredIntents={answeredIntents}
                                    questions={questions}
                                    onStepClick={onStepClick}
                                />
                            </div>
                        )}
                    </div>
                    {onCollapse && (
                        <button
                            type="button"
                            className="omniguide-cr-results__collapse-btn"
                            data-collapsed={true}
                            onClick={onCollapse}
                            onKeyDown={handleKeyDown}
                            aria-expanded="false"
                            aria-label="Expand recommendations"
                        >
                            <CollapseIcon />
                        </button>
                    )}
                </div>
            </div>
        );
    }

    // Shared results header — brand row (mark + "Shopping Guide" + "Based on"
    // answer chips, with X-close and top "Start over"), then the big intro.
    // Matches the PLP Variant 1 v2 comp; used by both the truncated and full views.
    const resultsHeader = (
        <div className="omniguide-cr-results__header">
            <div className="omniguide-cr-results__brand-row">
                <span className="omniguide-cr-results__brand">
                    <span className="omniguide-cr-results__brand-mark" aria-hidden="true">
                        {brandIconUrl ? (
                            <img className="omniguide-cr-results__brand-mark-img" src={brandIconUrl} alt="" />
                        ) : (
                            <DiamondMark />
                        )}
                    </span>
                    <span className="omniguide-cr-results__brand-label">{brandLabel}</span>
                </span>

                {questions.length > 0 && (
                    <div className="omniguide-cr-results__based-on">
                        <span className="omniguide-cr-results__based-on-label">Based on</span>
                        <div className="omniguide-cr-results__header-pills">
                            <DiscoveryStepIndicator
                                currentStep={-1}
                                totalSteps={questions.length}
                                answeredIntents={answeredIntents}
                                questions={questions}
                                onStepClick={onStepClick}
                            />
                        </div>
                    </div>
                )}

                <div className="omniguide-cr-results__header-actions">
                    {onCollapse && (
                        <button
                            type="button"
                            className="omniguide-cr-results__close-btn"
                            onClick={onCollapse}
                            aria-label="Close recommendations"
                        >
                            <CloseIcon />
                        </button>
                    )}
                    <button
                        type="button"
                        className="omniguide-cr-results__start-over-top"
                        onClick={() => {
                            onStartOver?.();
                            onBack?.();
                        }}
                    >
                        <RefreshIcon />
                        <span>Start over</span>
                    </button>
                </div>
            </div>

            <h2 className="omniguide-cr-results__title">We have some advice.</h2>
            <p className="omniguide-cr-results__subtitle">{introCopy}</p>
        </div>
    );

    // Show truncated state with "Show More" (mobile)
    if (isTruncated) {
        const firstProduct = recommendations[0]!;
        return (
            <div className="omniguide-cr-results omniguide-cr-results--truncated">
                {resultsHeader}

                {/* Truncated Product Preview */}
                <div className="omniguide-cr-results__truncated-content">
                    <div className="omniguide-cr-results__truncated-preview">
                        <div className="omniguide-cr-card-wrapper">
                            <CategoryProductCard
                                product={firstProduct}
                                index={0}
                                fallbackImage={fallbackImage}
                                showProductTags={showProductTags}
                                loading={isPreview}
                                onViewClick={onProductClick ? () => onProductClick(firstProduct, 0) : undefined}
                            />
                        </div>
                    </div>
                    <div className="omniguide-cr-results__truncated-fade" />
                </div>

                {/* Show More Button */}
                <div className="omniguide-cr-results__show-more-container">
                    <button
                        type="button"
                        className="omniguide-cr-results__show-more-btn"
                        onClick={onTruncatedToggle}
                    >
                        <span>Show More</span>
                        <ExpandIcon />
                    </button>
                </div>
            </div>
        );
    }

    // Determine grid className based on number of products
    const gridClassName = recommendations.length === 1
        ? 'omniguide-cr-results__grid omniguide-cr-results__grid--single'
        : 'omniguide-cr-results__grid';

    return (
        <div className="omniguide-cr-results">
            {resultsHeader}

            {/* Fallback Notice Banner */}
            <FallbackNotice fallbackInfo={fallbackInfo} />

            {/* Product Grid */}
            <div className={gridClassName}>
                {recommendations.map((product, index) => (
                    <div key={product.id ?? index} className="omniguide-cr-card-wrapper">
                        <CategoryProductCard
                            product={product}
                            index={index}
                            fallbackImage={fallbackImage}
                            showProductTags={showProductTags}
                            loading={isPreview}
                            onViewClick={onProductClick ? () => onProductClick(product, index) : undefined}
                            feedbackSlot={isPreview ? undefined : (
                                <div className="omniguide-cr-card__feedback">
                                    <DiscoveryFeedbackWidget
                                        entityId={product.sku ?? ''}
                                        entityType="category_recommendation"
                                        context={{
                                            product_name: product.name ?? product.display_name,
                                            recommendation_position: index === 0 ? 'top_pick' : 'runner_up',
                                        }}
                                        onSubmit={onFeedbackSubmit}
                                    />
                                </div>
                            )}
                        />
                    </div>
                ))}
            </div>

            {/* Footer */}
            <div className="omniguide-cr-results__footer">
                <span className="omniguide-cr-results__powered-by">
                    <SparkleIcon />
                    Powered by AI
                </span>
                <button
                    type="button"
                    className="omniguide-cr-results__start-over"
                    onClick={() => {
                        onStartOver?.();
                        onBack?.();
                    }}
                >
                    <RefreshIcon />
                    <span>Start Over</span>
                </button>
            </div>
        </div>
    );
}
