import React, { memo, useState, type ReactNode } from 'react';
import { formatPrice, safeHref } from '@swiftotter/omniguide-core';
import type { ProductReason } from '@swiftotter/omniguide-core';
import { ReviewInsightsToggle } from '../discovery/ReviewInsightsToggle.js';
import { ProductTag } from '../discovery/ProductTag.js';
import { parseMarkdownToHtml } from '../../utils/markdown.js';
import { UseCaseRatings } from './UseCaseRatings.js';
import type { UseCase } from './UseCaseRatings.js';

export interface CategoryProduct {
    id?: string | number;
    name?: string;
    display_name?: string;
    product_line?: string;
    price?: number | string | { value?: number };
    retail_price?: number | string | { value?: number };
    url?: string;
    path?: string;
    image_url?: string;
    imageUrl?: string;
    defaultImage?: { url?: string };
    sku?: string;
    tag?: { type: string };
    review_insights?: {
        average_rating?: number;
        review_count?: number;
        summary?: string;
        likes?: string[];
    };
    brand?: { name?: string };
    benefits?: string[];
    use_cases?: UseCase[];
    why?: string;
    critical_attributes?: string[];

    // -- Ranked-match fields (SOI-801/802, normalized by SOI-809) -------------
    // Optional and rendered conditionally; absent today unless the category
    // recommendation payload is run through normalizeRecommendedProduct().
    /** Match percentage 0–100 shown in the image pill. */
    matchPct?: number;
    /** Short "why this matches" statement. */
    summary?: string;
    /** Labeled reason chips (Best for / Feel / Value …). */
    reasons?: ProductReason[];
    /** One-paragraph "more details" explanation. */
    detail?: string;
}

export interface CategoryProductCardProps {
    product: CategoryProduct;
    index: number;
    /** Fallback image URL when product has no image (DI for site config) */
    fallbackImage?: string;
    /** Show "Top Pick" / "Runner-Up" tags (default: true) */
    showProductTags?: boolean;
    /**
     * Preview/loading mode. When true, fields that aren't yet present render as
     * skeleton placeholders instead of being hidden — used while the
     * `recommendations_preview` payload is on screen and the AI-generated copy
     * (image, "why this matches", reason chips) is still streaming in.
     */
    loading?: boolean;
    /** Click handler for the "View Now" link (analytics DI) */
    onViewClick?: () => void;
    /**
     * Optional feedback control ("Was this helpful?") rendered as an overlay at
     * the foot of the image column, rather than as a separate row below the card.
     */
    feedbackSlot?: ReactNode;
}

/**
 * CategoryProductCard displays a product with AI-generated content.
 * Handles both raw API data and BigCommerce hydrated data.
 */
export const CategoryProductCard = memo(function CategoryProductCard({ product, index, fallbackImage = '', showProductTags = true, loading = false, onViewClick, feedbackSlot }: CategoryProductCardProps): JSX.Element | null {
    const [detailOpen, setDetailOpen] = useState(false);

    if (!product) return null;

    const {
        name,
        display_name,
        product_line,
        price,
        retail_price,
        url,
        path,
        image_url,
        imageUrl,
        defaultImage,
        tag,
        review_insights,
        brand,
        benefits = [],
        use_cases = [],
        why,
        matchPct,
        summary,
        reasons = [],
        detail,
    } = product;

    // Resolve display name — prefer full name (includes brand) per SOI-271
    const displayName = name ?? display_name;

    // Resolve brand name (API format: product_line string, BC format: brand.name)
    const rawBrand = product_line ?? brand?.name ?? '';
    const brandName = rawBrand;
    // Strip brand prefix from display name to avoid visual duplication (brand shown on its own line)
    const cleanDisplayName = (rawBrand && displayName && displayName.toLowerCase().startsWith(rawBrand.toLowerCase() + ' '))
        ? displayName.slice(rawBrand.length).trimStart() || displayName
        : displayName;

    // Resolve image URL (API format: image_url, BC format: imageUrl or defaultImage.url).
    // Track the product's own image separately from the site fallback so preview
    // mode can show an image skeleton until the real image streams in, rather
    // than flashing the generic fallback.
    const ownImageUrl = image_url ?? imageUrl ?? defaultImage?.url;
    const resolvedImageUrl = ownImageUrl ?? fallbackImage;

    // Resolve product URL (API format: url, BC format: path) and gate it through a
    // scheme allow-list — a poisoned `javascript:` URL must not become a clickable href.
    const productUrl = safeHref(url ?? path);

    // Resolve price (API or BC format)
    const resolvedPrice = typeof price === 'object' ? price?.value : price;
    const resolvedRetailPrice = typeof retail_price === 'object' ? retail_price?.value : retail_price;

    // Get rating from review insights
    const averageRating = review_insights?.average_rating ?? 0;
    const reviewCount = review_insights?.review_count ?? 0;

    // Determine tag to display (use tag from API or fallback based on index)
    const displayTag = showProductTags ? (tag ?? { type: index === 0 ? 'recommended' : 'runner_up' }) : null;

    // Top pick (recommended / first) gets the emphasized layout + CTA.
    const isTopPick = index === 0;

    // "Why this matches" paragraph: prefer the concise summary, fall back to why.
    const summaryText = summary ?? why;
    // Expandable detail paragraph: prefer detail, fall back to the longer why.
    const detailText = detail ?? (summary ? why : undefined);

    // Reasons grid: prefer labeled reason chips, fall back to benefit strings.
    const reasonItems: Array<{ label?: string; value: string }> = (reasons.length > 0
        ? reasons.map((r) => ({ label: r.label, value: r.value }))
        : benefits.map((b) => ({ value: b }))
    ).filter((r) => r.value);
    const hasMatchPct = typeof matchPct === 'number' && Number.isFinite(matchPct);

    // Preview skeletons: in loading mode, fields that haven't arrived yet show a
    // shimmer placeholder instead of being hidden. Fields already present in the
    // preview payload (name, price, tag, match %, CTA) always render for real.
    const showImageSkeleton = loading && !ownImageUrl;
    const showBrandSkeleton = loading && !brandName;
    const showSummarySkeleton = loading && !summaryText;
    const showReasonsSkeleton = loading && reasonItems.length === 0;

    return (
        <div
            className={`omniguide-cr-card${isTopPick ? ' omniguide-cr-card--first' : ''}${loading ? ' omniguide-cr-card--loading' : ''}`}
            aria-busy={loading || undefined}
        >
            {/* Image Section with Badge */}
            <div className="omniguide-cr-card__image-section">
                {showImageSkeleton ? (
                    <div className="omniguide-cr-card__image omniguide-cr-card__image--skeleton" aria-hidden="true" />
                ) : (
                    <img
                        src={resolvedImageUrl}
                        alt={cleanDisplayName}
                        className="omniguide-cr-card__image"
                        onError={(e) => {
                            if (fallbackImage) {
                                (e.target as HTMLImageElement).src = fallbackImage;
                            }
                        }}
                    />
                )}
                {displayTag && <ProductTag tag={displayTag} classPrefix="omniguide-cr-card__badge" />}
                {hasMatchPct && (
                    <span className="omniguide-cr-card__match-pill">
                        <span className="omniguide-cr-card__match-dot" aria-hidden="true" />
                        {Math.round(matchPct as number)}% match
                    </span>
                )}
                {feedbackSlot}
            </div>

            {/* Body (right column) */}
            <div className="omniguide-cr-card__body">
                {/* Head: brand eyebrow, name, price + stars, CTA */}
                <div className="omniguide-cr-card__content">
                    <div className="omniguide-cr-card__columns-container">
                        <div className="omniguide-cr-card__columns-text">
                            <div className="omniguide-cr-card__brand-row">
                                {brandName ? (
                                    <p className="omniguide-cr-card__brand">{brandName}</p>
                                ) : showBrandSkeleton ? (
                                    <span className="omniguide-cr-card__sk omniguide-cr-card__sk--eyebrow" aria-hidden="true" />
                                ) : null}
                                <h3 className="omniguide-cr-card__name">{cleanDisplayName}</h3>
                            </div>
                            <div className="omniguide-cr-card__price-group">
                                <span className="omniguide-cr-card__price">{formatPrice(resolvedPrice)}</span>
                                {resolvedRetailPrice && Number(resolvedRetailPrice) > Number(resolvedPrice) && (
                                    <span className="omniguide-cr-card__price omniguide-cr-card__price--original">{formatPrice(resolvedRetailPrice)}</span>
                                )}
                                {averageRating > 0 && (
                                    <ReviewInsightsToggle
                                        rating={averageRating}
                                        reviewCount={reviewCount}
                                        summary={review_insights?.summary}
                                        likes={review_insights?.likes}
                                    />
                                )}
                            </div>
                        </div>
                        <div className="omniguide-cr-card__actions">
                            {productUrl ? (
                                <a href={productUrl} className="omniguide-cr-card__view-btn" onClick={onViewClick}>
                                    {isTopPick ? 'Buy Top Pick' : 'View Product'}
                                    <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
                                        <path d="M6 12L10 8L6 4" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
                                    </svg>
                                </a>
                            ) : (
                                <button type="button" className="omniguide-cr-card__view-btn" onClick={onViewClick}>
                                    {isTopPick ? 'Buy Top Pick' : 'View Product'}
                                    <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
                                        <path d="M6 12L10 8L6 4" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
                                    </svg>
                                </button>
                            )}
                        </div>
                    </div>
                </div>

                {/* "Why this matches" summary paragraph */}
                {summaryText ? (
                    <p
                        className="omniguide-cr-card__summary"
                        dangerouslySetInnerHTML={parseMarkdownToHtml(summaryText)}
                    />
                ) : showSummarySkeleton ? (
                    <div className="omniguide-cr-card__summary-skeleton" aria-hidden="true">
                        <span className="omniguide-cr-card__sk omniguide-cr-card__sk--line" />
                        <span className="omniguide-cr-card__sk omniguide-cr-card__sk--line" />
                        <span className="omniguide-cr-card__sk omniguide-cr-card__sk--line omniguide-cr-card__sk--line-short" />
                    </div>
                ) : null}

                {/* Reasons — two-column green-check grid */}
                {reasonItems.length > 0 ? (
                    <ul className="omniguide-cr-card__reasons">
                        {reasonItems.slice(0, 6).map((reason, i) => (
                            <li key={reason.label ? `${reason.label}:${reason.value}` : reason.value ?? i} className="omniguide-cr-card__reason">
                                <span className="omniguide-cr-card__reason-check" aria-hidden="true">
                                    <svg viewBox="0 0 20 20" fill="currentColor">
                                        <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                                    </svg>
                                </span>
                                <span className="omniguide-cr-card__reason-text">
                                    {reason.label && <b>{reason.label}: </b>}
                                    {reason.value && <span className="omniguide-cr-card__reason-value">{reason.value}</span>}
                                </span>
                            </li>
                        ))}
                    </ul>
                ) : showReasonsSkeleton ? (
                    <ul className="omniguide-cr-card__reasons omniguide-cr-card__reasons--skeleton" aria-hidden="true">
                        {Array.from({ length: isTopPick ? 4 : 2 }).map((_, i) => (
                            // eslint-disable-next-line react/no-array-index-key -- fixed-length skeleton placeholders, never reordered
                            <li key={i} className="omniguide-cr-card__reason">
                                <span className="omniguide-cr-card__sk omniguide-cr-card__sk--check" />
                                <span className="omniguide-cr-card__sk omniguide-cr-card__sk--line" />
                            </li>
                        ))}
                    </ul>
                ) : null}

                {/* Use Case ratings (legacy data — kept conditional) */}
                {use_cases.length > 0 && (
                    <div className="omniguide-cr-card__use-cases">
                        <UseCaseRatings useCases={use_cases} maxItems={4} />
                    </div>
                )}

                {/* "More details" expandable */}
                {detailText && (
                    <div className="omniguide-cr-card__more">
                        <button
                            type="button"
                            className={`omniguide-cr-card__more-toggle${detailOpen ? ' omniguide-cr-card__more-toggle--open' : ''}`}
                            onClick={() => setDetailOpen((v) => !v)}
                            aria-expanded={detailOpen}
                            aria-controls={`omniguide-cr-card-detail-${product.sku ?? index}`}
                        >
                            {detailOpen ? 'Less details' : 'More details'}
                            <svg width="14" height="14" viewBox="0 0 20 20" fill="currentColor">
                                <path fillRule="evenodd" d="M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z" clipRule="evenodd" />
                            </svg>
                        </button>
                        {detailOpen && (
                            <p
                                id={`omniguide-cr-card-detail-${product.sku ?? index}`}
                                className="omniguide-cr-card__detail"
                                dangerouslySetInnerHTML={parseMarkdownToHtml(detailText)}
                            />
                        )}
                    </div>
                )}
            </div>
        </div>
    );
});
