/**
 * useCategoryWebSocket
 *
 * Manages WebSocket connection for category recommendations.
 * Supports conversational flow where questions are received one at a time.
 * Platform-agnostic — hydration is injected via options.
 */

import { useState, useRef, useCallback, useEffect } from 'react';
import { FLOW_STATES, logger, normalizeQuestions, normalizeRecommendedProducts, emitRecommendations } from '@swiftotter/omniguide-core';
import type { FlowState, OmniguideProduct, RecommendationMatch } from '@swiftotter/omniguide-core';
import { useStatusMessage } from './useStatusMessage.js';
import { useDiscoveryAnswerStorage } from './useDiscoveryAnswerStorage.js';
import type { DiscoveryAnswerStorageAdapter } from './useDiscoveryAnswerStorage.js';

// =========================================
// Types
// =========================================

export interface CategoryHydration {
  hydrateProducts: (products: Record<string, unknown>[]) => Promise<Record<string, unknown>[]>;
}

export interface CategoryWebSocketFactory {
  create: (config: {
    onMessage: (msg: Record<string, unknown>) => void;
    onStatusChange: (status: string) => void;
    onError: (err: Error) => void;
  }) => CategoryWebSocketInstance;
}

export interface CategoryWebSocketInstance {
  connect: () => Promise<void>;
  disconnect: () => void;
  isConnected: () => boolean;
  sendStartMessage: (categoryUrl: string, firstAnswer?: Record<string, unknown> | null) => void;
  sendResumeMessage: (categoryUrl: string, answeredIntents: Record<string, unknown>) => void;
  sendAnswerMessage: (questionId: string, answerId: string | null, answerText: string) => void;
  sendRecommendationRequest?: (categoryUrl: string, answeredIntents: Record<string, unknown>, options?: Record<string, unknown>) => void;
}

export interface UseCategoryWebSocketOptions {
  /** Hydration functions for enriching products with platform data */
  hydration: CategoryHydration;
  /** Factory to create WebSocket instances */
  wsFactory: CategoryWebSocketFactory;
  /** Storage adapter for persisting answers */
  storageAdapter: DiscoveryAnswerStorageAdapter;
  /** Product type ID for filtering stored answers */
  productTypeId?: number | string | null;
}

export const CATEGORY_STATUS_MESSAGES: Record<string, string | string[]> = {
  analyzing_preferences: [
    'Analyzing your preferences...',
    'Understanding what you\'re looking for...',
    'Reviewing your selections...',
    'Almost there, processing your choices...',
  ],
  finding_products: [
    'Finding matching products...',
    'Searching for the perfect match...',
    'Discovering great options for you...',
    'This is taking shape, hang tight...',
  ],
  expanding_search: [
    'Expanding search for better matches...',
    'Looking for even more options...',
    'Widening the search to find the best fit...',
    'Just a moment, we\'re being thorough...',
  ],
  generating_insights: [
    'Generating product insights...',
    'Analyzing product details...',
    'Building your personalized results...',
    'Almost ready, finalizing details...',
  ],
  finalizing: [
    'Finalizing recommendations...',
    'Putting the finishing touches...',
    'Getting everything ready for you...',
    'Just a few more seconds...',
  ],
  processing: [
    'Processing...',
    'Working on it...',
    'Almost there...',
    'Just a moment...',
  ],
};

/**
 * Bridge resolved category recommendations to pure-DOM host decorators
 * (PLP grid match ribbons, SOI-813) via the recommendation bus. SSR-safe;
 * skips products without a SKU.
 */
function publishPlpRecommendations(products: OmniguideProduct[]): void {
  const matches: RecommendationMatch[] = products
    .filter((p) => !!p.sku)
    .map(({ sku, matchPct, rank }) => ({ sku, matchPct, rank }));
  emitRecommendations({ page: 'plp', products: matches });
}

// =========================================
// Hook
// =========================================

export function useCategoryWebSocket({
  hydration,
  wsFactory,
  storageAdapter,
  productTypeId = null,
}: UseCategoryWebSocketOptions) {
  const [connectionStatus, setConnectionStatus] = useState('disconnected');

  // Conversational flow state
  const [flowState, setFlowState] = useState<FlowState>(FLOW_STATES.IDLE);
  const [currentQuestion, setCurrentQuestion] = useState<Record<string, unknown> | null>(null);
  const [questionNumber, setQuestionNumber] = useState(0);
  const [isLastQuestion, setIsLastQuestion] = useState(false);
  const [answeredQuestions, setAnsweredQuestions] = useState<Array<{ question: unknown; answer: { answer_id: string | null; answer: string } }>>([]);

  // Results state
  const [recommendations, setRecommendations] = useState<Record<string, unknown>[]>([]);
  const [productCards, setProductCards] = useState<Record<string, unknown>[]>([]);
  // True while a `recommendations_preview` payload is on screen and the final
  // `recommendations` message (with AI copy + hydrated images) is still in
  // flight. Drives the cards' skeleton-field rendering.
  const [previewActive, setPreviewActive] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<Error | null>(null);
  // Optional results intro/advice copy, supplied by the backend in the
  // `recommendations` message as `review_summary` (legacy alias: `intro_text`).
  // Null when absent — the UI then falls back to a category-based default.
  const [resultsIntro, setResultsIntro] = useState<string | null>(null);

  // Status message state
  const [processingStatus, setProcessingStatus] = useState<string | null>(null);

  // Fallback information state
  const [fallbackInfo, setFallbackInfo] = useState({
    used: false, reason: null as string | null, scope: null as string | null, explanation: null as string | null,
  });

  // "Other" answer state
  const [otherValidationError, setOtherValidationError] = useState<{ message: string } | null>(null);
  const [clarificationPrompt, setClarificationPrompt] = useState<string | null>(null);
  const [isOtherProcessing, setIsOtherProcessing] = useState(false);

  const wsRef = useRef<CategoryWebSocketInstance | null>(null);
  const requestInProgressRef = useRef(false);
  const categoryUrlRef = useRef<string | null>(null);
  const questionNumberRef = useRef(questionNumber);

  // Shared hooks
  const { saveAnswer, restoreFromStorage, hasStoredSession, getStoredAnswerCount, clearStorage } = useDiscoveryAnswerStorage(storageAdapter, productTypeId);
  const { getStatusMessage } = useStatusMessage(processingStatus, CATEGORY_STATUS_MESSAGES);

  useEffect(() => {
    questionNumberRef.current = questionNumber;
  }, [questionNumber]);

  useEffect(() => {
    return () => {
      if (wsRef.current) {
        wsRef.current.disconnect();
        wsRef.current = null;
      }
    };
  }, []);

  const disconnectWebSocket = useCallback(() => {
    if (wsRef.current) {
      wsRef.current.disconnect();
      wsRef.current = null;
      setConnectionStatus('disconnected');
    }
  }, []);

  const createMessageHandler = useCallback((msg: Record<string, unknown>) => {
    switch (msg['type']) {
      case 'question': {
        const rawQuestion = msg['question'] as Record<string, unknown>;
        // Normalize WebSocket question to match DiscoveryQuestion shape
        // (backend sends question_id/question_text/answer_text, components expect id/question/text)
        const normalized = normalizeQuestions({ questions: [rawQuestion] } as Parameters<typeof normalizeQuestions>[0]);
        setCurrentQuestion((normalized[0] as unknown as Record<string, unknown>) ?? rawQuestion);
        setQuestionNumber((msg['question_number'] as number) || questionNumberRef.current + 1);
        setIsLastQuestion(!!(msg['is_last']));
        setFlowState(FLOW_STATES.QUESTIONING);
        setIsLoading(false);
        break;
      }

      case 'resumed': {
        const answeredCount = (msg['answered_count'] as number) || 0;
        setQuestionNumber(answeredCount);
        break;
      }

      case 'status': {
        const status = msg['status'] as string;
        setProcessingStatus(status);
        if (status === 'questions_complete') {
          setFlowState(FLOW_STATES.LOADING_RESULTS);
          setIsLoading(true);
          setCurrentQuestion(null);
        } else if (status === 'processing' || status === 'analyzing_preferences') {
          setIsLoading(true);
        }
        break;
      }

      case 'recommendations_preview': {
        // Early payload: ranked products with the basics (name/price/url/tag/
        // score) but no images or AI copy yet. Render the cards immediately so
        // the user sees their picks taking shape; missing fields show as
        // skeletons until the final `recommendations` message lands. The socket
        // stays open — this is not a terminal message.
        const rawPreview = (msg['products'] as Record<string, unknown>[]) || [];
        const normalizedPreview = normalizeRecommendedProducts(rawPreview);
        setRecommendations(normalizedPreview as unknown as Record<string, unknown>[]);
        setProductCards([]);
        setPreviewActive(true);
        setProcessingStatus(null);
        setIsLoading(false);
        setFlowState(FLOW_STATES.COMPLETE);
        break;
      }

      case 'recommendations': {
        setFallbackInfo({
          used: !!(msg['fallback_used']),
          reason: (msg['fallback_reason'] as string) || null,
          scope: (msg['fallback_scope'] as string) || null,
          explanation: (msg['fallback_explanation'] as string) || null,
        });

        const introText = msg['review_summary'] ?? msg['intro_text'];
        setResultsIntro(typeof introText === 'string' && introText.trim() ? introText : null);

        const rawProducts = (msg['products'] as Record<string, unknown>[]) || [];
        // Normalize so the backend's documented match fields populate matchPct
        // and rank (aliases: match_pct / match_percentage / match_score / score,
        // and rank) along with summary/bullets/detail/reasons. This is what the
        // result cards' match pill and the PLP match-ribbon bus read.
        const normalizedProducts = normalizeRecommendedProducts(rawProducts);
        setRecommendations(normalizedProducts as unknown as Record<string, unknown>[]);
        setProductCards([]);
        disconnectWebSocket();

        if (normalizedProducts.length > 0) {
          setProcessingStatus('finalizing');
          hydration.hydrateProducts(normalizedProducts as unknown as Record<string, unknown>[])
            .then((hydratedProducts) => {
              // Re-apply the normalized match fields in case hydration rebuilt
              // the product objects (catalog data still wins for name/price/img).
              const merged = hydratedProducts.map((hp, i) => ({
                ...(normalizedProducts[i] as Record<string, unknown> | undefined),
                ...hp,
              }));
              setRecommendations(merged);
              publishPlpRecommendations(merged as unknown as OmniguideProduct[]);
              setPreviewActive(false);
              setIsLoading(false);
              setProcessingStatus(null);
              setError(null);
              setFlowState(FLOW_STATES.COMPLETE);
              requestInProgressRef.current = false;
            })
            .catch(() => {
              setPreviewActive(false);
              setIsLoading(false);
              setProcessingStatus(null);
              setError(null);
              setFlowState(FLOW_STATES.COMPLETE);
              requestInProgressRef.current = false;
            });
        } else {
          setPreviewActive(false);
          setIsLoading(false);
          setProcessingStatus(null);
          setError(null);
          setFlowState(FLOW_STATES.COMPLETE);
          requestInProgressRef.current = false;
        }
        break;
      }

      case 'answer_response': {
        setIsOtherProcessing(false);
        if (msg['validation_failed']) {
          setOtherValidationError({ message: (msg['error_message'] as string) || 'Invalid answer. Please try again.' });
          setIsLoading(false);
        } else if (msg['needs_clarification']) {
          setClarificationPrompt((msg['clarification_prompt'] as string) || 'Please provide more details.');
          setIsLoading(false);
        } else if (msg['has_next_question']) {
          setOtherValidationError(null);
          setClarificationPrompt(null);
        } else if (msg['is_terminal']) {
          setOtherValidationError(null);
          setClarificationPrompt(null);
          setFlowState(FLOW_STATES.LOADING_RESULTS);
          setIsLoading(true);
          setCurrentQuestion(null);
        }
        break;
      }

      case 'done':
        setPreviewActive(false);
        setIsLoading(false);
        setProcessingStatus(null);
        requestInProgressRef.current = false;
        disconnectWebSocket();
        break;

      case 'error': {
        const rawError = (msg['content'] as string) || 'Unknown error';
        logger.error('Category WebSocket error:', rawError);
        setError(new Error('We encountered an error while processing your request. Please try again.'));
        setPreviewActive(false);
        setIsLoading(false);
        setProcessingStatus(null);
        setFlowState(FLOW_STATES.ERROR);
        requestInProgressRef.current = false;
        disconnectWebSocket();
        break;
      }
    }
  }, [disconnectWebSocket, hydration]);

  const connectWebSocket = useCallback(async () => {
    disconnectWebSocket();

    const ws = wsFactory.create({
      onMessage: createMessageHandler,
      onStatusChange: setConnectionStatus,
      onError: (err: Error) => {
        logger.error('Category WebSocket connection error:', err.message);
        setError(err);
        setIsLoading(false);
        setProcessingStatus(null);
        setFlowState(FLOW_STATES.ERROR);
        requestInProgressRef.current = false;
        disconnectWebSocket();
      },
    });

    wsRef.current = ws;
    await ws.connect();
    return ws;
  }, [wsFactory, createMessageHandler, disconnectWebSocket]);

  const resetForNewRequest = useCallback(() => {
    setIsLoading(true);
    setError(null);
    setRecommendations([]);
    setProductCards([]);
    setPreviewActive(false);
    setResultsIntro(null);
    setProcessingStatus('analyzing_preferences');
    setFallbackInfo({ used: false, reason: null, scope: null, explanation: null });
    setFlowState(FLOW_STATES.CONNECTING);
  }, []);

  const startConversation = useCallback(async (
    categoryUrl: string,
    firstAnswer: { questionId: string; answerId: string | null; answerText: string } | null = null,
    firstQuestion: Record<string, unknown> | null = null,
  ) => {
    if (requestInProgressRef.current) return;
    requestInProgressRef.current = true;
    categoryUrlRef.current = categoryUrl;

    resetForNewRequest();

    if (firstAnswer && firstQuestion) {
      setAnsweredQuestions([{
        question: firstQuestion,
        answer: { answer_id: firstAnswer.answerId, answer: firstAnswer.answerText },
      }]);
      setQuestionNumber(1);
      saveAnswer(firstAnswer.questionId, firstAnswer.answerId, firstAnswer.answerText, firstAnswer.answerId === null, firstQuestion);
    } else {
      setAnsweredQuestions([]);
      setQuestionNumber(0);
    }

    try {
      const ws = await connectWebSocket();
      ws.sendStartMessage(categoryUrl, firstAnswer);
    } catch (err) {
      logger.error('Category WebSocket startConversation failed:', err instanceof Error ? err.message : String(err));
      setError(err instanceof Error ? err : new Error(String(err)));
      setIsLoading(false);
      setProcessingStatus(null);
      setFlowState(FLOW_STATES.ERROR);
      requestInProgressRef.current = false;
      disconnectWebSocket();
    }
  }, [connectWebSocket, disconnectWebSocket, resetForNewRequest, saveAnswer]);

  const resumeSession = useCallback(async (categoryUrl: string) => {
    const restoredAnswers = restoreFromStorage();
    if (restoredAnswers.length === 0) return false;
    if (requestInProgressRef.current) return false;

    requestInProgressRef.current = true;
    categoryUrlRef.current = categoryUrl;

    setAnsweredQuestions(restoredAnswers);
    setQuestionNumber(restoredAnswers.length);
    resetForNewRequest();

    try {
      const ws = await connectWebSocket();
      const answeredIntents = storageAdapter.getForApi(productTypeId);
      ws.sendResumeMessage(categoryUrl, answeredIntents);
      return true;
    } catch (err) {
      logger.error('Category WebSocket resumeSession failed:', err instanceof Error ? err.message : String(err));
      setError(err instanceof Error ? err : new Error(String(err)));
      setIsLoading(false);
      setProcessingStatus(null);
      setFlowState(FLOW_STATES.ERROR);
      requestInProgressRef.current = false;
      disconnectWebSocket();
      return false;
    }
  }, [connectWebSocket, disconnectWebSocket, resetForNewRequest, restoreFromStorage, storageAdapter, productTypeId]);

  const submitAnswer = useCallback((questionId: string, answerId: string | null, answerText: string, question: Record<string, unknown>) => {
    if (!wsRef.current || !wsRef.current.isConnected()) return;

    setAnsweredQuestions((prev) => [...prev, {
      question,
      answer: { answer_id: answerId, answer: answerText },
    }]);

    saveAnswer(questionId, answerId, answerText, false, question);
    setIsLoading(true);
    setCurrentQuestion(null);
    wsRef.current.sendAnswerMessage(questionId, answerId, answerText);
  }, [saveAnswer]);

  const submitOtherAnswer = useCallback((questionId: string, answerText: string, question: Record<string, unknown>) => {
    if (!wsRef.current || !wsRef.current.isConnected()) return;

    setOtherValidationError(null);
    setIsOtherProcessing(true);
    setIsLoading(true);

    setAnsweredQuestions((prev) => [...prev, {
      question,
      answer: { answer_id: null, answer: answerText },
    }]);

    saveAnswer(questionId, null, answerText, true, question);
    wsRef.current.sendAnswerMessage(questionId, null, answerText);
  }, [saveAnswer]);

  const clearOtherError = useCallback(() => {
    setOtherValidationError(null);
  }, []);

  const resetConversation = useCallback(() => {
    disconnectWebSocket();
    clearStorage();
    setFlowState(FLOW_STATES.IDLE);
    setCurrentQuestion(null);
    setQuestionNumber(0);
    setIsLastQuestion(false);
    setAnsweredQuestions([]);
    setRecommendations([]);
    setProductCards([]);
    setPreviewActive(false);
    setResultsIntro(null);
    setIsLoading(false);
    setError(null);
    setProcessingStatus(null);
    setFallbackInfo({ used: false, reason: null, scope: null, explanation: null });
    setOtherValidationError(null);
    setClarificationPrompt(null);
    setIsOtherProcessing(false);
    requestInProgressRef.current = false;
  }, [disconnectWebSocket, clearStorage]);

  /**
   * Non-conversational flow: send a single recommendation request with pre-collected answers.
   * Used when questions are gathered upfront (traditional flow) rather than one-at-a-time.
   */
  const getRecommendations = useCallback(async (
    categoryUrl: string,
    answeredIntents: Record<string, unknown>,
    options: Record<string, unknown> = {},
  ) => {
    if (requestInProgressRef.current) return;
    requestInProgressRef.current = true;
    categoryUrlRef.current = categoryUrl;

    setIsLoading(true);
    setError(null);
    setRecommendations([]);
    setProductCards([]);
    setPreviewActive(false);
    setResultsIntro(null);
    setProcessingStatus('analyzing_preferences');
    setFallbackInfo({ used: false, reason: null, scope: null, explanation: null });

    disconnectWebSocket();

    try {
      const ws = wsFactory.create({
        onMessage: createMessageHandler,
        onStatusChange: setConnectionStatus,
        onError: (err: Error) => {
          logger.error('Category WebSocket connection error (getRecommendations):', err.message);
          setError(err);
          setIsLoading(false);
          setProcessingStatus(null);
          requestInProgressRef.current = false;
          disconnectWebSocket();
        },
      });

      wsRef.current = ws;
      await ws.connect();

      if (ws.sendRecommendationRequest) {
        ws.sendRecommendationRequest(categoryUrl, answeredIntents, options);
      }
    } catch (err) {
      logger.error('Category WebSocket getRecommendations failed:', err instanceof Error ? err.message : String(err));
      setError(err instanceof Error ? err : new Error(String(err)));
      setIsLoading(false);
      setProcessingStatus(null);
      requestInProgressRef.current = false;
      disconnectWebSocket();
    }
  }, [wsFactory, createMessageHandler, disconnectWebSocket]);

  const disconnect = useCallback(() => {
    disconnectWebSocket();
  }, [disconnectWebSocket]);

  return {
    connectionStatus,
    flowState,
    currentQuestion,
    questionNumber,
    isLastQuestion,
    answeredQuestions,
    recommendations,
    productCards,
    previewActive,
    isLoading,
    error,
    processingStatus,
    fallbackInfo,
    resultsIntro,
    otherValidationError,
    clarificationPrompt,
    isOtherProcessing,
    getStatusMessage,
    startConversation,
    resumeSession,
    submitAnswer,
    submitOtherAnswer,
    clearOtherError,
    resetConversation,
    getRecommendations,
    disconnect,
    hasStoredSession,
    getStoredAnswerCount,
  };
}
